# --- Sigma Point Generation ---

def sigma_points(x, P, alpha=1e-3, beta=2.0, kappa=0.0):
    """
    Generate 2n+1 sigma points and their weights.

    Parameters
    ----------
    x     : state mean (n,)
    P     : state covariance (n, n)
    alpha : spread of sigma points (typically 1e-3)
    beta  : distribution parameter (2 optimal for Gaussian)
    kappa : secondary scaling (typically 0)

    Returns
    -------
    sigmas : (2n+1, n) sigma point matrix
    Wm     : (2n+1,)  mean weights
    Wc     : (2n+1,)  covariance weights
    """
