    lam = alpha ** 2 * (n + kappa) - n

    # Cholesky decomposition for matrix square root
    U = cholesky((n + lam) * P, lower=False)  # upper-triangular: rows are sqrt columns

    sigmas = np.zeros((2 * n + 1, n))
